-- Modify "bom_items" table
ALTER TABLE "bom_items" ADD CONSTRAINT "bom_items_production_operation_allowed" CHECK ((production_operation_code IS NULL) OR ((production_operation_code)::text = 'FABRIC_PROCESSING'::text)), ADD COLUMN "production_operation_code" character varying NULL;
-- Modify "production_order_material_requirements" table
ALTER TABLE "production_order_material_requirements" ADD CONSTRAINT "production_order_material_requirements_operation_allowed" CHECK ((production_operation_code IS NULL) OR ((production_operation_code)::text = 'FABRIC_PROCESSING'::text)), ADD COLUMN "production_operation_code" character varying NULL;
-- Create index "productionordermaterialrequirement_production_order_item_id_pro" to table: "production_order_material_requirements"
CREATE INDEX "productionordermaterialrequirement_production_order_item_id_pro" ON "production_order_material_requirements" ("production_order_item_id", "production_operation_code");
-- Modify "production_wip_batches" table
ALTER TABLE "production_wip_batches" DROP CONSTRAINT "production_wip_batches_execution_bundle", DROP COLUMN "outsourcing_order_item_id";
-- Create "production_wip_outsourcing_allocations" table
CREATE TABLE "production_wip_outsourcing_allocations" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "subject_type" character varying NOT NULL,
  "allocated_quantity" numeric(20,6) NOT NULL,
  "created_at" timestamptz NOT NULL,
  "outsourcing_order_item_id" bigint NOT NULL,
  "production_order_material_requirement_id" bigint NULL,
  "production_wip_batch_id" bigint NOT NULL,
  "unit_id" bigint NOT NULL,
  "created_by" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "production_wip_outsourcing_allocations_admin_users_creator" FOREIGN KEY ("created_by") REFERENCES "admin_users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_wip_outsourcing_allocations_outsourcing_order_items_" FOREIGN KEY ("outsourcing_order_item_id") REFERENCES "outsourcing_order_items" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_wip_outsourcing_allocations_production_order_materia" FOREIGN KEY ("production_order_material_requirement_id") REFERENCES "production_order_material_requirements" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_wip_outsourcing_allocations_production_wip_batches_o" FOREIGN KEY ("production_wip_batch_id") REFERENCES "production_wip_batches" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_wip_outsourcing_allocations_units_unit" FOREIGN KEY ("unit_id") REFERENCES "units" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_wip_outsourcing_allocations_quantity_positive" CHECK (allocated_quantity > (0)::numeric),
  CONSTRAINT "production_wip_outsourcing_allocations_subject_allowed" CHECK ((subject_type)::text = ANY ((ARRAY['PRODUCT'::character varying, 'MATERIAL'::character varying])::text[])),
  CONSTRAINT "production_wip_outsourcing_allocations_subject_bundle" CHECK ((((subject_type)::text = 'PRODUCT'::text) AND (production_order_material_requirement_id IS NULL)) OR (((subject_type)::text = 'MATERIAL'::text) AND (production_order_material_requirement_id IS NOT NULL)))
);
-- Create index "productionwipoutsourcingallocation_outsourcing_order_item_id" to table: "production_wip_outsourcing_allocations"
CREATE UNIQUE INDEX "productionwipoutsourcingallocation_outsourcing_order_item_id" ON "production_wip_outsourcing_allocations" ("outsourcing_order_item_id");
-- Create index "productionwipoutsourcingallocation_production_wip_batch_id" to table: "production_wip_outsourcing_allocations"
CREATE INDEX "productionwipoutsourcingallocation_production_wip_batch_id" ON "production_wip_outsourcing_allocations" ("production_wip_batch_id");
-- Create index "productionwipoutsourcingallocation_production_wip_batch_id_outs" to table: "production_wip_outsourcing_allocations"
CREATE UNIQUE INDEX "productionwipoutsourcingallocation_production_wip_batch_id_outs" ON "production_wip_outsourcing_allocations" ("production_wip_batch_id", "outsourcing_order_item_id");
-- Create index "productionwipoutsourcingallocation_production_wip_batch_id_prod" to table: "production_wip_outsourcing_allocations"
CREATE UNIQUE INDEX "productionwipoutsourcingallocation_production_wip_batch_id_prod" ON "production_wip_outsourcing_allocations" ("production_wip_batch_id", "production_order_material_requirement_id") WHERE (production_order_material_requirement_id IS NOT NULL);
